class Playground {
  async run(inputs) {
    const chars = inputs[0].split(',').map(x => x.trim());
    this.array.init(chars);
    this.log('Find first unique (non-repeating) character');
    await this.await();

    this.log('📊 Pass 1: Count character frequencies');
    await this.await();

    for (let i = 0; i < chars.length; i++) {
      const char = chars[i];
      this.ptr.set('i', i);
      this.array.highlight(i, '#3b82f6');

      const count = this.hashmap.has(char) ? this.hashmap.get(char) : 0;
      this.hashmap.put(char, count + 1);
      this.log(`'${char}' → count = ${count + 1}`);
      await this.await();

      this.array.highlight(i, '#64748b');
    }

    this.ptr.remove('i');
    this.array.clearHighlights();
    this.log('📋 Frequency count complete. Now find first unique...');
    await this.await();

    this.log('🔍 Pass 2: Find first character with count = 1');
    await this.await();

    for (let i = 0; i < chars.length; i++) {
      const char = chars[i];
      this.ptr.set('i', i);
      this.array.highlight(i, '#f59e0b');

      const count = this.hashmap.get(char);
      this.hashmap.highlight(char, '#f59e0b');
      this.log(`'${char}' has count = ${count}`);
      await this.await();

      if (count === 1) {
        this.array.highlight(i, '#10b981');
        this.hashmap.highlight(char, '#10b981');
        this.log(`✅ Found! '${char}' at index ${i} is the first unique character`);
        await this.await();
        this.ptr.remove('i');
        return i;
      }

      this.array.highlight(i, '#ef4444');
      this.log(`'${char}' is not unique, continue...`);
      await this.await();
    }

    this.ptr.remove('i');
    this.log('❌ No unique character found');
    await this.await();
    return -1;
  }
}
